mapper.select:
SELECT deviceId, roleId, lastMessageTimestamp, summary, promptTokens, completionTokens, createTime
FROM sys_summary
WHERE 1=1

    AND deviceId = #{deviceId}


    AND roleId = #{roleId}

ORDER BY createTime DESC

mapper.delete:
DELETE FROM sys_summary
WHERE roleId = #{roleId}
AND deviceId = #{deviceId}

    AND createTime = #{createTime,jdbcType=TIMESTAMP}
